$file = 'lib\messages_screen.dart'
$c = [System.IO.File]::ReadAllText($file, [System.Text.Encoding]::UTF8)
$c = $c -replace "`r`n", "`n"  # normalize
$n = 0

# 1. Update _showContextMenu to include functional Pin, Archive, Mute, Mark as Unread
$oldMenu = "  void _showContextMenu(BuildContext context, String partnerId, String name) {`n    HapticFeedback.mediumImpact();`n    showModalBottomSheet(`n      context: context,`n      backgroundColor: const Color(0xFF1B202D),`n      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(20))),`n      builder: (ctx) {`n        return SafeArea(`n          child: Column(`n            mainAxisSize: MainAxisSize.min,`n            children: [`n              Container(`n                margin: const EdgeInsets.only(top: 8, bottom: 16),`n                width: 40, height: 4,`n                decoration: BoxDecoration(color: Colors.white24, borderRadius: BorderRadius.circular(2)),`n              ),`n              ListTile(`n                leading: const Icon(Icons.push_pin_outlined, color: Colors.white),`n                title: const Text('Pin chat', style: TextStyle(color: Colors.white)),`n                onTap: () { Navigator.pop(ctx); },`n              ),`n              ListTile(`n                leading: const Icon(Icons.archive_outlined, color: Colors.white),`n                title: const Text('Archive chat', style: TextStyle(color: Colors.white)),`n                onTap: () { Navigator.pop(ctx); },`n              ),`n              ListTile(`n                leading: const Icon(Icons.notifications_off_outlined, color: Colors.white),`n                title: const Text('Mute notifications', style: TextStyle(color: Colors.white)),`n                onTap: () { Navigator.pop(ctx); },`n              ),`n              ListTile(`n                leading: const Icon(Icons.mark_chat_unread_outlined, color: Colors.white),`n                title: const Text('Mark as unread', style: TextStyle(color: Colors.white)),`n                onTap: () { Navigator.pop(ctx); },`n              ),`n              ListTile(`n                leading: const Icon(Icons.delete_outline, color: Color(0xFFEF4444)),`n                title: const Text('Delete chat', style: TextStyle(color: Color(0xFFEF4444))),`n                onTap: () {`n                  Navigator.pop(ctx);`n                  _confirmDeleteChat(context, partnerId, name);`n                },`n              ),`n            ],`n          ),`n        );`n      }`n    );`n  }"

$newMenu = "  void _showContextMenu(BuildContext context, String partnerId, String name) {`n    HapticFeedback.mediumImpact();`n    final isPinned = _pinnedIds.contains(partnerId);`n    final isArchived = _archivedIds.contains(partnerId);`n    final isMutedVal = _mutedUntilMap[partnerId];`n    final isMuted = isMutedVal != null && isMutedVal.isAfter(DateTime.now());`n`n    showModalBottomSheet(`n      context: context,`n      backgroundColor: const Color(0xFF1B202D),`n      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(20))),`n      builder: (ctx) {`n        return SafeArea(`n          child: Column(`n            mainAxisSize: MainAxisSize.min,`n            children: [`n              Container(`n                margin: const EdgeInsets.only(top: 8, bottom: 16),`n                width: 40, height: 4,`n                decoration: BoxDecoration(color: Colors.white24, borderRadius: BorderRadius.circular(2)),`n              ),`n              ListTile(`n                leading: Icon(isPinned ? Icons.push_pin : Icons.push_pin_outlined, color: Colors.white),`n                title: Text(isPinned ? 'Unpin chat' : 'Pin chat', style: const TextStyle(color: Colors.white)),`n                onTap: () {`n                  Navigator.pop(ctx);`n                  setState(() {`n                    if (isPinned) {`n                      _pinnedIds.remove(partnerId);`n                    } else {`n                      if (_pinnedIds.length >= 3) {`n                        ScaffoldMessenger.of(context).showSnackBar(`n                          const SnackBar(content: Text('You can only pin up to 3 chats'), backgroundColor: Color(0xFFFF0055)),`n                        );`n                      } else {`n                        _pinnedIds.add(partnerId);`n                      }`n                    }`n                  });`n                },`n              ),`n              ListTile(`n                leading: Icon(isArchived ? Icons.unarchive_outlined : Icons.archive_outlined, color: Colors.white),`n                title: Text(isArchived ? 'Unarchive chat' : 'Archive chat', style: const TextStyle(color: Colors.white)),`n                onTap: () {`n                  Navigator.pop(ctx);`n                  setState(() {`n                    if (isArchived) {`n                      _archivedIds.remove(partnerId);`n                      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Chat unarchived')));`n                    } else {`n                      _archivedIds.add(partnerId);`n                      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Chat archived')));`n                    }`n                  });`n                },`n              ),`n              ListTile(`n                leading: Icon(isMuted ? Icons.notifications_active_outlined : Icons.notifications_off_outlined, color: Colors.white),`n                title: Text(isMuted ? 'Unmute notifications' : 'Mute notifications', style: const TextStyle(color: Colors.white)),`n                onTap: () {`n                  Navigator.pop(ctx);`n                  if (isMuted) {`n                    setState(() => _mutedUntilMap.remove(partnerId));`n                    ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Notifications unmuted')));`n                  } else {`n                    _showMuteOptions(context, partnerId);`n                  }`n                },`n              ),`n              ListTile(`n                leading: const Icon(Icons.mark_chat_unread_outlined, color: Colors.white),`n                title: const Text('Mark as unread', style: TextStyle(color: Colors.white)),`n                onTap: () {`n                  Navigator.pop(ctx);`n                  setState(() => _manuallyUnreadIds.add(partnerId));`n                  ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Marked as unread')));`n                },`n              ),`n              ListTile(`n                leading: const Icon(Icons.delete_outline, color: Color(0xFFEF4444)),`n                title: const Text('Delete chat', style: TextStyle(color: Color(0xFFEF4444))),`n                onTap: () {`n                  Navigator.pop(ctx);`n                  _confirmDeleteChat(context, partnerId, name);`n                },`n              ),`n            ],`n          ),`n        );`n      }`n    );`n  }"

if ($c.Contains($oldMenu)) { $c = $c.Replace($oldMenu, $newMenu); $n++ } else { Write-Host "MISS: _showContextMenu replacement" }

# 2. Add _showMuteOptions helper method
$muteHelper = "  void _showMuteOptions(BuildContext context, String partnerId) {`n    showModalBottomSheet(`n      context: context,`n      backgroundColor: const Color(0xFF1B202D),`n      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(20))),`n      builder: (ctx) {`n        return SafeArea(`n          child: Column(`n            mainAxisSize: MainAxisSize.min,`n            children: [`n              const Padding(`n                padding: EdgeInsets.all(16.0),`n                child: Text('Mute Notifications', style: TextStyle(color: Colors.white, fontSize: 16, fontWeight: FontWeight.bold)),`n              ),`n              ListTile(`n                title: const Text('For 1 Hour', style: TextStyle(color: Colors.white70)),`n                onTap: () {`n                  setState(() => _mutedUntilMap[partnerId] = DateTime.now().add(const Duration(hours: 1)));`n                  Navigator.pop(ctx);`n                  ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Muted for 1 Hour')));`n                },`n              ),`n              ListTile(`n                title: const Text('For 8 Hours', style: TextStyle(color: Colors.white70)),`n                onTap: () {`n                  setState(() => _mutedUntilMap[partnerId] = DateTime.now().add(const Duration(hours: 8)));`n                  Navigator.pop(ctx);`n                  ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Muted for 8 Hours')));`n                },`n              ),`n              ListTile(`n                title: const Text('Until I turn it back on', style: TextStyle(color: Colors.white70)),`n                onTap: () {`n                  setState(() => _mutedUntilMap[partnerId] = DateTime.now().add(const Duration(days: 3650)));`n                  Navigator.pop(ctx);`n                  ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Muted indefinitely')));`n                },`n              ),`n            ],`n          ),`n        );`n      }`n    );`n  }"

# Insert after _showContextMenu
$c = $c.Replace($newMenu, $newMenu + "`n`n" + $muteHelper)

# 3. Update _confirmDeleteChat to perform actual Supabase deletion
$oldConfirm = "  void _confirmDeleteChat(BuildContext context, String partnerId, String name) {`n    showDialog(`n      context: context,`n      builder: (ctx) => AlertDialog(`n        backgroundColor: const Color(0xFF1B202D),`n        title: Text('Delete chat with `$name?', style: const TextStyle(color: Colors.white)),`n        content: const Text('This will delete the chat only for you.', style: TextStyle(color: Colors.white70)),`n        actions: [`n          TextButton(`n            onPressed: () => Navigator.pop(ctx),`n            child: const Text('Cancel', style: TextStyle(color: Colors.white54)),`n          ),`n          TextButton(`n            onPressed: () {`n              Navigator.pop(ctx);`n              setState(() {`n                _conversations.removeWhere((e) => e.key == partnerId);`n              });`n            },`n            child: const Text('Delete', style: TextStyle(color: Color(0xFFEF4444))),`n          ),`n        ],`n      )`n    );`n  }"

$newConfirm = "  void _confirmDeleteChat(BuildContext context, String partnerId, String name) {`n    showDialog(`n      context: context,`n      builder: (ctx) => AlertDialog(`n        backgroundColor: const Color(0xFF1B202D),`n        title: Text('Delete chat with `$name?', style: const TextStyle(color: Colors.white)),`n        content: const Text('This will delete the chat for both users.', style: TextStyle(color: Colors.white70)),`n        actions: [`n          TextButton(`n            onPressed: () => Navigator.pop(ctx),`n            child: const Text('Cancel', style: TextStyle(color: Colors.white54)),`n          ),`n          TextButton(`n            onPressed: () async {`n              Navigator.pop(ctx);`n              final backup = List<MapEntry<String, Map<String, dynamic>>>.from(_conversations);`n              setState(() {`n                _conversations.removeWhere((e) => e.key == partnerId);`n              });`n              try {`n                await Supabase.instance.client`n                    .from('messages')`n                    .delete()`n                    .or('and(sender_id.eq.`$_myUid,receiver_id.eq.`$partnerId),and(sender_id.eq.`$partnerId,receiver_id.eq.`$_myUid)');`n                if (context.mounted) {`n                  ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('Conversation deleted from database')));`n                }`n              } catch (e) {`n                if (mounted) setState(() => _conversations = backup);`n                if (context.mounted) {`n                  ScaffoldMessenger.of(context).showSnackBar(SnackBar(content: Text('Failed to delete: `$e'), backgroundColor: const Color(0xFFFF0055)));`n                }`n              }`n            },`n            child: const Text('Delete', style: TextStyle(color: Color(0xFFEF4444))),`n          ),`n        ],`n      )`n    );`n  }"

if ($c.Contains($oldConfirm)) { $c = $c.Replace($oldConfirm, $newConfirm); $n++ } else { Write-Host "MISS: _confirmDeleteChat replacement" }

$c = $c -replace "`n", "`r`n"  # restore
[System.IO.File]::WriteAllText($file, $c, [System.Text.Encoding]::UTF8)
Write-Host "Done. Applied $n replacements."
